INSERT INTO knowledge_base (id, software, category, keywords, title, content, code, property, hint)
VALUES
  ('pp-interface-project-panel', 'premiere', 'interface', ARRAY['بروجكت','project','لوحة','panel','ملفات','مشروع','بانل','استيراد'], 'لوحة Project', 'لوحة Project تعرض كل ملفات المشروع. رتّبها بفولدرات (Bins) بكليك يمين → New Bin. ابحث بالاسم من شريط البحث فوق.', NULL, NULL, NULL),
  ('pp-interface-timeline-panel', 'premiere', 'interface', ARRAY['تايم لاين','timeline','لوحة','panel','مونتاج','تراكات','tracks'], 'لوحة Timeline', 'التايم لاين هو مكان المونتاج. التراكات الفيديو فوق (V1, V2...) والصوت تحت (A1, A2...). اسحب الكليبات وقصها هنا.', NULL, NULL, NULL),
  ('pp-interface-program-monitor', 'premiere', 'interface', ARRAY['بروقرام','program','مونيتور','monitor','معاينة','preview','شاشة'], 'Program Monitor', 'يعرض نتيجة المونتاج من التايم لاين. استخدمه للمعاينة النهائية. غيّر جودة المعاينة من القائمة تحت (Full, 1/2, 1/4).', NULL, NULL, NULL),
  ('pp-interface-source-monitor', 'premiere', 'interface', ARRAY['سورس','source','مونيتور','monitor','كليب','مصدر','قبل المونتاج'], 'Source Monitor', 'يعرض الكليب قبل إضافته للتايم لاين. حدد In (I) و Out (O) ثم اسحب للتايم لاين أو اضغط , (insert) أو . (overwrite).', NULL, NULL, NULL),
  ('pp-interface-effects-panel', 'premiere', 'interface', ARRAY['إفكتات','effects','لوحة','تأثيرات','فلاتر','ترانزيشن'], 'لوحة Effects', 'تحتوي كل الإفكتات والترانزيشنات. ابحث بالاسم أو تصفح الفولدرات. اسحب الإفكت على الكليب لتطبيقه.', NULL, NULL, NULL),
  ('pp-interface-effect-controls', 'premiere', 'interface', ARRAY['إفكت كونترول','effect controls','تحكم','إعدادات','كيفريم','keyframe'], 'لوحة Effect Controls', 'تتحكم بإعدادات الإفكتات على الكليب المختار. هنا تضيف keyframes وتعدّل القيم. Motion و Opacity موجودين دائماً.', NULL, NULL, NULL),
  ('pp-interface-audio-mixer', 'premiere', 'interface', ARRAY['أوديو ميكسر','audio mixer','صوت','مكسر','فيدر','fader','مستوى'], 'Audio Track Mixer', 'يتحكم بمستوى صوت كل تراك. الفيدرات تتحرك لايف. أضف إفكتات صوت من الخانات فوق الفيدر.', NULL, NULL, NULL),
  ('pp-interface-essential-graphics', 'premiere', 'interface', ARRAY['إسنشال قرافيكس','essential graphics','عناوين','titles','نصوص','MOGRT'], 'لوحة Essential Graphics', 'لإنشاء وتعديل العناوين والنصوص. فيها قوالب MOGRT جاهزة. اختر Browse للقوالب أو Edit لتعديل العنوان المختار.', NULL, NULL, NULL),
  ('pp-interface-essential-sound', 'premiere', 'interface', ARRAY['إسنشال ساوند','essential sound','صوت','حوار','موسيقى','dialogue','music'], 'لوحة Essential Sound', 'تصنّف الصوت (Dialogue, Music, SFX, Ambience) وتعطيك أدوات سريعة: تنظيف الحوار، ducking الموسيقى، تعديل الـ loudness.', NULL, NULL, NULL),
  ('pp-interface-lumetri-scopes', 'premiere', 'interface', ARRAY['لوميتري سكوب','lumetri scopes','waveform','ويفورم','ألوان','تحليل'], 'Lumetri Scopes', 'تحليل الألوان بصرياً. Waveform للسطوع، Vectorscope للتشبع واللون، Parade لكل قناة RGB. افتحها من Window → Lumetri Scopes.', NULL, NULL, NULL),
  ('pp-interface-workspaces', 'premiere', 'interface', ARRAY['ووركسبيس','workspace','تخطيط','layout','ترتيب','لوحات'], 'Workspaces', 'تخطيطات جاهزة للوحات. Editing للمونتاج، Color للتلوين، Audio للصوت. غيّرها من Window → Workspaces أو الشريط فوق.', NULL, NULL, NULL),
  ('pp-interface-save-workspace', 'premiere', 'interface', ARRAY['حفظ ووركسبيس','save workspace','تخطيط مخصص','custom layout'], 'حفظ Workspace مخصص', 'رتّب اللوحات كما تحب، ثم Window → Workspaces → Save as New Workspace. سمّه وراح يظهر بالقائمة.', NULL, NULL, NULL),
  ('pp-interface-reset-workspace', 'premiere', 'interface', ARRAY['ريست','reset','إعادة','workspace','ترتيب أصلي'], 'إعادة ضبط Workspace', 'إذا خربطت اللوحات: Window → Workspaces → Reset to Saved Layout. يرجّع الترتيب الأصلي.', NULL, NULL, NULL),
  ('pp-interface-fullscreen-panel', 'premiere', 'interface', ARRAY['فول سكرين','fullscreen','تكبير','لوحة كاملة','~'], 'تكبير لوحة للشاشة كاملة', 'اضغط ~ (التلدة) على أي لوحة لتكبيرها ملء الشاشة. اضغط مرة ثانية للرجوع.', NULL, NULL, NULL),
  ('pp-import-basic', 'premiere', 'import', ARRAY['استيراد','import','إضافة','ملفات','فيديو','جلب'], 'استيراد ملفات', 'File → Import أو Ctrl+I أو اسحب الملفات مباشرة للوحة Project. يقبل فيديو، صوت، صور، وتسلسلات صور.', NULL, NULL, NULL),
  ('pp-import-media-browser', 'premiere', 'import', ARRAY['ميديا براوزر','media browser','تصفح','استعراض','ملفات'], 'Media Browser', 'لوحة لتصفح الملفات من داخل بريمير. مفيدة للكاميرات والـ folders الكبيرة. دبل كليك للاستيراد.', NULL, NULL, NULL),
  ('pp-import-formats', 'premiere', 'import', ARRAY['صيغ','formats','أنواع','ملفات مدعومة','MP4','MOV','MXF'], 'الصيغ المدعومة', 'بريمير يدعم: MP4, MOV, MXF, AVI, MKV, ProRes, DNxHR, H.264, H.265, RAW من أغلب الكاميرات. إذا ما يقرأ صيغة، حوّلها لـ ProRes.', NULL, NULL, NULL),
  ('pp-import-image-sequence', 'premiere', 'import', ARRAY['تسلسل صور','image sequence','PNG sequence','فريمات'], 'استيراد تسلسل صور', 'اختر أول صورة، فعّل Image Sequence بالأسفل، ثم Import. يجمعها ككليب فيديو واحد. تأكد الترقيم متسلسل.', NULL, NULL, NULL),
  ('pp-import-psd-layers', 'premiere', 'import', ARRAY['فوتوشوب','PSD','طبقات','layers','استيراد'], 'استيراد PSD بالطبقات', 'عند استيراد PSD، اختر Import As: Individual Layers للحصول على كل طبقة منفصلة، أو Merged Layers لصورة واحدة.', NULL, NULL, NULL),
  ('pp-import-aep', 'premiere', 'import', ARRAY['أفتر إفكتس','After Effects','AEP','Dynamic Link','ربط'], 'استيراد مشروع After Effects', 'File → Import واختر ملف .aep. يعرض الـ compositions كملفات. Dynamic Link يحدّثها تلقائياً لما تعدّل بـ AE.', NULL, NULL, NULL),
  ('pp-import-ingest', 'premiere', 'import', ARRAY['إنجست','ingest','نسخ','transcode','استيراد تلقائي'], 'Ingest Settings', 'File → Project Settings → Ingest. فعّل Ingest لنسخ/تحويل الملفات تلقائياً عند الاستيراد. مفيد لإنشاء proxies تلقائية.', NULL, NULL, NULL),
  ('pp-proxy-create', 'premiere', 'import', ARRAY['بروكسي','proxy','إنشاء','create','ملفات خفيفة','سرعة'], 'إنشاء Proxies', 'كليك يمين على الكليبات → Proxy → Create Proxies. اختر preset (مثل 1024x540 ProRes). ينتظر Media Encoder يرندرها.', NULL, NULL, NULL),
  ('pp-proxy-toggle', 'premiere', 'import', ARRAY['بروكسي','proxy','تبديل','toggle','أصلي'], 'التبديل بين Proxy والأصلي', 'الزر بالتايم لاين (أيقونة مربعين). أو أضفه من Button Editor. الأزرق = proxy، الرمادي = أصلي. التصدير دائماً بالأصلي.', NULL, NULL, NULL),
  ('pp-proxy-attach', 'premiere', 'import', ARRAY['بروكسي','proxy','ربط','attach','جاهز'], 'ربط Proxy جاهز', 'إذا عندك proxies جاهزة: كليك يمين → Proxy → Attach Proxies. اختر الملفات. لازم نفس الاسم أو تطابق يدوي.', NULL, NULL, NULL),
  ('pp-media-cache', 'premiere', 'import', ARRAY['ميديا كاش','media cache','كاش','cache','ملفات مؤقتة','تنظيف'], 'Media Cache', 'بريمير ينشئ ملفات cache لتسريع العرض. Preferences → Media Cache. غيّر مكانها لـ SSD سريع. Delete لحذف الكاش القديم.', NULL, NULL, NULL),
  ('pp-media-cache-clean', 'premiere', 'import', ARRAY['تنظيف كاش','clean cache','مساحة','حذف','ملفات مؤقتة'], 'تنظيف Media Cache', 'Preferences → Media Cache → Delete. أو Delete Unused لحذف كاش الملفات غير المستخدمة فقط. يوفّر مساحة كبيرة.', NULL, NULL, NULL),
  ('pp-relink-media', 'premiere', 'import', ARRAY['ريلنك','relink','مفقود','offline','ضايع','ملف مفقود'], 'إعادة ربط ملفات مفقودة', 'إذا ظهرت Media Offline: كليك يمين → Link Media. حدد موقع الملف الجديد. فعّل Align Timecode لملفات الكاميرا.', NULL, NULL, NULL),
  ('pp-offline-media', 'premiere', 'import', ARRAY['أوفلاين','offline','ملف ضايع','أحمر','مفقود'], 'ملف Offline (أحمر)', 'الكليب الأحمر بالتايم لاين = ملف مفقود. كليك يمين → Link Media وحدد مكانه. أو File → Link Media للكل مرة وحدة.', NULL, NULL, NULL),
  ('pp-interpret-footage', 'premiere', 'import', ARRAY['إنتربريت','interpret','فريم ريت','ألفا','تفسير'], 'Interpret Footage', 'كليك يمين → Modify → Interpret Footage. غيّر frame rate، alpha channel، field order. مفيد لتصحيح سرعة الفيديو الخاطئة.', NULL, NULL, NULL),
  ('pp-bins-organize', 'premiere', 'import', ARRAY['بن','bin','فولدر','folder','تنظيم','ترتيب'], 'تنظيم بـ Bins', 'كليك يمين بالـ Project → New Bin. سمّ الفولدرات: Footage, Audio, Graphics, Sequences. التنظيم يوفر وقت كثير.', NULL, NULL, NULL),
  ('pp-labels-color', 'premiere', 'import', ARRAY['ليبل','label','لون','color','تمييز','تصنيف'], 'تلوين الكليبات (Labels)', 'كليك يمين → Label واختر لون. استخدم ألوان مختلفة للفيديو/الصوت/الموسيقى. يسهّل التمييز بالتايم لاين.', NULL, NULL, NULL),
  ('pp-timeline-sequence-create', 'premiere', 'timeline', ARRAY['سيكونس','sequence','إنشاء','create','تايم لاين جديد','مشروع'], 'إنشاء Sequence جديد', 'File → New → Sequence أو Ctrl+N. اختر preset يطابق الكاميرا (مثل DSLR 1080p24). أو اسحب كليب للـ New Item لإنشاء sequence يطابقه.', NULL, NULL, NULL),
  ('pp-timeline-sequence-settings', 'premiere', 'timeline', ARRAY['إعدادات سيكونس','sequence settings','frame rate','resolution'], 'تغيير إعدادات Sequence', 'Sequence → Sequence Settings. غيّر الأبعاد، frame rate، preview codec. تحذير: تغيير frame rate بعد المونتاج يخرب التوقيت.', NULL, NULL, NULL),
  ('pp-timeline-tracks-add', 'premiere', 'timeline', ARRAY['تراك','track','إضافة','add','مسار','طبقة'], 'إضافة تراكات', 'كليك يمين على header التراكات → Add Tracks. حدد عدد تراكات Video و Audio. أو اسحب كليب لمنطقة فارغة يُنشئ تراك جديد.', NULL, NULL, NULL),
  ('pp-timeline-cut-razor', 'premiere', 'timeline', ARRAY['قص','cut','razor','ريزر','تقطيع','شفرة','C'], 'قص بأداة Razor', 'اضغط C للتبديل لأداة Razor. انقر على الكليب لقصه. Shift+C يقص كل التراكات معاً. رجّع للسهم بـ V.', NULL, NULL, NULL),
  ('pp-timeline-cut-playhead', 'premiere', 'timeline', ARRAY['قص عند المؤشر','cut at playhead','Ctrl+K','قطع سريع'], 'قص عند Playhead', 'Ctrl+K يقص الكليب المستهدف عند موقع المؤشر. أسرع من الـ Razor لقطع واحد.', NULL, NULL, NULL),
  ('pp-timeline-delete', 'premiere', 'timeline', ARRAY['حذف','delete','مسح','شيل','كليب'], 'حذف كليب', 'اختر الكليب واضغط Delete. يحذف ويترك فراغ (gap). استخدم Ripple Delete لإغلاق الفراغ.', NULL, NULL, NULL),
  ('pp-timeline-ripple-delete', 'premiere', 'timeline', ARRAY['ريبل ديليت','ripple delete','حذف وسد','Shift+Delete','بدون فراغ'], 'Ripple Delete', 'اختر الكليب واضغط Shift+Delete (أو كليك يمين → Ripple Delete). يحذف الكليب ويسد الفراغ تلقائياً.', NULL, NULL, NULL),
  ('pp-timeline-ripple-edit', 'premiere', 'timeline', ARRAY['ريبل إديت','ripple edit','تريم مع إزاحة','B'], 'Ripple Edit', 'اضغط B للتبديل لأداة Ripple Edit. اسحب الحافة — الكليبات بعده تتحرك معه. يحافظ على التسلسل بدون فراغات.', NULL, NULL, NULL),
  ('pp-timeline-roll-edit', 'premiere', 'timeline', ARRAY['رول إديت','roll edit','تريم مزدوج','N'], 'Roll Edit', 'اضغط N. اسحب نقطة القطع بين كليبين — يقصر واحد ويطوّل الثاني. المدة الكلية ما تتغير.', NULL, NULL, NULL),
  ('pp-timeline-slip-edit', 'premiere', 'timeline', ARRAY['سليب','slip','تحريك المحتوى','Y'], 'Slip Edit', 'اضغط Y. اسحب الكليب — المحتوى يتحرك داخل الإطار، لكن موقعه ومدته بالتايم لاين ثابتة. مفيد لضبط اللقطة.', NULL, NULL, NULL),
  ('pp-timeline-slide-edit', 'premiere', 'timeline', ARRAY['سلايد','slide','تحريك مع التأثير','U'], 'Slide Edit', 'اضغط U. اسحب الكليب — يتحرك بمكانه، والكليبات المجاورة تتقصر/تتطول للتعويض. المدة الكلية ثابتة.', NULL, NULL, NULL),
  ('pp-timeline-snap', 'premiere', 'timeline', ARRAY['سناب','snap','مغناطيس','التصاق','S'], 'Snap (المغناطيس)', 'اضغط S لتفعيل/إيقاف المغناطيس. يلصق الكليبات ببعض وبالمؤشر وبالماركرات. شغّله للدقة، طفّه للحرية.', NULL, NULL, NULL),
  ('pp-timeline-in-out', 'premiere', 'timeline', ARRAY['إن','آوت','in','out','I','O','نقطة بداية','نقطة نهاية'], 'In و Out Points', 'I يحدد نقطة البداية، O يحدد النهاية. تستخدم للتصدير جزء، أو إدراج كليب من Source Monitor. Alt+I أو Alt+O لمسحها.', NULL, NULL, NULL),
  ('pp-timeline-markers', 'premiere', 'timeline', ARRAY['ماركر','marker','علامة','M','تحديد','ملاحظة'], 'Markers', 'M يضيف marker عند المؤشر. دبل كليك لإضافة ملاحظة أو لون. استخدمها لتحديد اللقطات المهمة أو نقاط الإيقاع.', NULL, NULL, NULL),
  ('pp-timeline-track-targeting', 'premiere', 'timeline', ARRAY['تارقتنق','targeting','استهداف','V1','A1'], 'Track Targeting', 'الأزرار V1, V2, A1 على يسار التراكات. الأزرق = مفعّل. يحدد أين ينزل الكليب لما تضغط , أو . أو تسحب من Source.', NULL, NULL, NULL),
  ('pp-timeline-sync-lock', 'premiere', 'timeline', ARRAY['سينك لوك','sync lock','قفل','تزامن'], 'Sync Lock', 'أيقونة القفل بجانب اسم التراك. يمنع التراك من التحرك عند الـ ripple edits. استخدمه للموسيقى لتبقى ثابتة.', NULL, NULL, NULL),
  ('pp-timeline-nest', 'premiere', 'timeline', ARRAY['نست','nest','تجميع','دمج','كليب واحد'], 'Nest Clips', 'اختر عدة كليبات → كليك يمين → Nest. تصير كليب واحد. مفيد للإفكتات الجماعية أو التنظيم. دبل كليك لفتح الـ nest.', NULL, NULL, NULL),
  ('pp-timeline-group', 'premiere', 'timeline', ARRAY['قروب','group','تجميع','ربط','Ctrl+G'], 'Group Clips', 'اختر كليبات → Ctrl+G. تتحرك معاً لكن تبقى منفصلة (مو مثل Nest). Ctrl+Shift+G لفك المجموعة.', NULL, NULL, NULL),
  ('pp-timeline-link-unlink', 'premiere', 'timeline', ARRAY['لينك','link','ربط','فصل','صوت وفيديو'], 'Link/Unlink', 'كليك يمين → Unlink يفصل الصوت عن الفيديو. Link يربطهم. مفيد لتحريك الصوت مستقل أو حذف صوت بس.', NULL, NULL, NULL),
  ('pp-timeline-match-frame', 'premiere', 'timeline', ARRAY['ماتش فريم','match frame','F','الكليب الأصلي'], 'Match Frame', 'F على كليب بالتايم لاين = يفتحه بالـ Source Monitor عند نفس الفريم. مفيد لإيجاد footage زايد قبل/بعد.', NULL, NULL, NULL),
  ('pp-timeline-playback', 'premiere', 'timeline', ARRAY['تشغيل','play','space','مسافة','إيقاف'], 'تشغيل/إيقاف', 'Space للتشغيل/الإيقاف. J عكسي، K إيقاف، L للأمام. اضغط L مرتين للسرعة 2x. J+K = عكسي بطيء.', NULL, NULL, NULL),
  ('pp-timeline-zoom', 'premiere', 'timeline', ARRAY['زوم','zoom','تكبير','تصغير','+','-','\'], 'زوم التايم لاين', '+ تكبير، - تصغير، \ لرؤية الكل. أو اسحب شريط الزوم تحت التايم لاين. Alt+Scroll للزوم أفقي.', NULL, NULL, NULL),
  ('pp-transition-apply', 'premiere', 'transitions', ARRAY['ترانزيشن','transition','انتقال','تطبيق','إضافة'], 'تطبيق Transition', 'اسحب الترانزيشن من لوحة Effects على نقطة القطع بين كليبين. أو اختر القطع واضغط Ctrl+D للـ default transition.', NULL, NULL, NULL),
  ('pp-transition-default', 'premiere', 'transitions', ARRAY['ديفولت','default','ترانزيشن افتراضي','Ctrl+D'], 'Default Transition', 'Ctrl+D يطبق الترانزيشن الافتراضي (Cross Dissolve عادةً). لتغييره: كليك يمين على ترانزيشن → Set as Default.', NULL, NULL, NULL),
  ('pp-transition-duration', 'premiere', 'transitions', ARRAY['مدة ترانزيشن','transition duration','طول','ثواني'], 'تغيير مدة Transition', 'اسحب حافة الترانزيشن بالتايم لاين. أو دبل كليك واكتب المدة. أو Preferences → Timeline → Default Transition Duration.', NULL, NULL, NULL),
  ('pp-transition-cross-dissolve', 'premiere', 'transitions', ARRAY['كروس ديزولف','cross dissolve','ذوبان','تلاشي','فيد'], 'Cross Dissolve', 'أشهر ترانزيشن. يدمج نهاية كليب مع بداية الثاني بشفافية. مثالي لمرور الوقت أو تغيير المشهد الناعم.', NULL, NULL, NULL),
  ('pp-transition-dip-black', 'premiere', 'transitions', ARRAY['دب تو بلاك','dip to black','أسود','فيد أسود'], 'Dip to Black', 'يتلاشى للأسود ثم يظهر الكليب الثاني. مثالي لنهاية المشاهد أو الفصل بين أجزاء.', NULL, NULL, NULL),
  ('pp-transition-dip-white', 'premiere', 'transitions', ARRAY['دب تو وايت','dip to white','أبيض','فلاش'], 'Dip to White', 'يتلاشى للأبيض. يعطي إحساس فلاش أو ذكرى أو حلم. استخدمه بحذر — مو لكل مشهد.', NULL, NULL, NULL),
  ('pp-transition-wipe', 'premiere', 'transitions', ARRAY['وايب','wipe','مسح','انتقال جانبي'], 'Wipe Transitions', 'الصورة تُمسح بأشكال مختلفة (Linear, Radial, Clock). تبدو قديمة نوعاً ما. تصلح للستايل الريترو أو الكوميدي.', NULL, NULL, NULL),
  ('pp-transition-audio-crossfade', 'premiere', 'transitions', ARRAY['كروس فيد صوت','audio crossfade','انتقال صوت','صوت'], 'Audio Crossfade', 'Shift+Ctrl+D للـ default audio transition. أو اسحب من Effects → Audio Transitions. يدمج نهاية صوت مع بداية الثاني.', NULL, NULL, NULL),
  ('pp-transition-constant-power', 'premiere', 'transitions', ARRAY['كونستنت باور','constant power','انتقال صوت ناعم'], 'Constant Power', 'الـ default للصوت. يحافظ على مستوى الصوت ثابت أثناء الـ crossfade. أفضل للحوار والموسيقى.', NULL, NULL, NULL),
  ('pp-transition-exponential', 'premiere', 'transitions', ARRAY['إكسبوننشال','exponential fade','فيد سريع'], 'Exponential Fade', 'الصوت يختفي بسرعة ثم يبطئ. مفيد لنهاية الموسيقى أو المشهد. يعطي إحساس طبيعي أكثر.', NULL, NULL, NULL),
  ('pp-transition-handles', 'premiere', 'transitions', ARRAY['هاندلز','handles','footage زايد','مقابض'], 'Transition Handles', 'الترانزيشن يحتاج footage زايد (handles) قبل/بعد نقطة القطع. إذا ما في زيادة، يظهر تحذير أو يقصر الكليب.', NULL, NULL, NULL),
  ('pp-audio-essential-panel', 'premiere', 'audio', ARRAY['إسنشال ساوند','essential sound','تصنيف صوت','حوار'], 'Essential Sound Panel', 'Window → Essential Sound. صنّف الكليب: Dialogue للحوار، Music للموسيقى، SFX للمؤثرات، Ambience للخلفية. كل صنف له أدوات مختلفة.', NULL, NULL, NULL),
  ('pp-audio-dialogue-enhance', 'premiere', 'audio', ARRAY['تحسين حوار','dialogue enhance','صوت أوضح','كلام'], 'تحسين الحوار', 'اختر الكليب → Essential Sound → Dialogue. فعّل Enhance Speech. يزيل الضوضاء ويوضّح الصوت تلقائياً.', NULL, NULL, NULL),
  ('pp-audio-noise-reduction', 'premiere', 'audio', ARRAY['إزالة ضوضاء','noise reduction','تشويش','هيس','خلفية'], 'إزالة الضوضاء', 'Essential Sound → Dialogue → Repair → Reduce Noise. ابدأ بقيمة قليلة (2-4). الزيادة تخرب جودة الصوت.', NULL, NULL, NULL),
  ('pp-audio-reduce-reverb', 'premiere', 'audio', ARRAY['ريفيرب','reverb','صدى','غرفة','دوي'], 'إزالة الصدى (Reverb)', 'Essential Sound → Dialogue → Repair → Reduce Reverb. يقلل صدى الغرفة. مو سحري — التسجيل النظيف أفضل.', NULL, NULL, NULL),
  ('pp-audio-dehum', 'premiere', 'audio', ARRAY['ديهم','dehum','طنين','كهرباء','50hz','60hz'], 'إزالة طنين الكهرباء', 'Essential Sound → Dialogue → Repair → DeHum. اختر 50Hz (أوروبا/آسيا) أو 60Hz (أمريكا). يزيل طنين الكهرباء.', NULL, NULL, NULL),
  ('pp-audio-ducking', 'premiere', 'audio', ARRAY['دكنق','ducking','خفض موسيقى','تلقائي','صوت فوق موسيقى'], 'Auto Ducking', 'صنّف الموسيقى كـ Music، والحوار كـ Dialogue. Essential Sound → Music → Ducking → فعّله. الموسيقى تنخفض تلقائياً لما في حوار.', NULL, NULL, NULL),
  ('pp-audio-loudness', 'premiere', 'audio', ARRAY['لاودنس','loudness','LUFS','مستوى صوت','نورملايز'], 'Loudness Normalization', 'Essential Sound → اختر الصنف → Loudness → Auto Match. يوحّد مستوى الصوت. للـ YouTube استهدف -14 LUFS.', NULL, NULL, NULL),
  ('pp-audio-track-mixer', 'premiere', 'audio', ARRAY['تراك ميكسر','track mixer','مكسر','فيدر','مستوى تراك'], 'Audio Track Mixer', 'Window → Audio Track Mixer. فيدرات لكل تراك. حرّكها لتعديل المستوى. أضف إفكتات من الخانات فوق الفيدر.', NULL, NULL, NULL),
  ('pp-audio-keyframes', 'premiere', 'audio', ARRAY['كيفريم صوت','audio keyframes','أوتوميشن','تحريك صوت'], 'Keyframes للصوت', 'وسّع التراك بالتايم لاين، اضغط على الخط الأبيض + Ctrl لإضافة keyframe. اسحب النقاط لتغيير المستوى عبر الوقت.', NULL, NULL, NULL),
  ('pp-audio-eq', 'premiere', 'audio', ARRAY['إكولايزر','EQ','equalizer','ترددات','باص','تريبل'], 'Parametric Equalizer', 'Effects → Parametric Equalizer. يتحكم بالترددات. Low للباص، High للحدة. قص الترددات السيئة أفضل من رفع الجيدة.', NULL, NULL, NULL),
  ('pp-audio-compressor', 'premiere', 'audio', ARRAY['كومبريسر','compressor','ضغط صوت','دايناميك'], 'Compressor', 'يقلل الفرق بين الأصوات العالية والمنخفضة. يوحّد مستوى الحوار. Threshold يحدد متى يبدأ، Ratio قوة الضغط.', NULL, NULL, NULL),
  ('pp-audio-limiter', 'premiere', 'audio', ARRAY['ليميتر','limiter','سقف صوت','كليبنق'], 'Hard Limiter', 'يمنع الصوت من تجاوز حد معين. Maximum Amplitude = -1dB لتجنب الـ clipping. آخر شي بالسلسلة.', NULL, NULL, NULL),
  ('pp-color-lumetri-basic', 'premiere', 'color', ARRAY['لوميتري','lumetri','تلوين أساسي','basic correction'], 'Lumetri Basic Correction', 'Window → Lumetri Color → Basic Correction. Exposure للسطوع، Contrast للتباين، Highlights/Shadows للتفاصيل، Whites/Blacks للحدود.', NULL, NULL, NULL),
  ('pp-color-white-balance', 'premiere', 'color', ARRAY['وايت بالانس','white balance','توازن أبيض','حرارة','درجة حرارة'], 'White Balance', 'Lumetri → Basic → Temperature (برتقالي/أزرق) و Tint (أخضر/بنفسجي). أو استخدم WB Selector وانقر على شي أبيض بالصورة.', NULL, NULL, NULL),
  ('pp-color-exposure', 'premiere', 'color', ARRAY['إكسبوجر','exposure','سطوع','تعريض'], 'Exposure', 'Lumetri → Basic → Exposure. يرفع/يخفض السطوع الكلي. راقب الـ Waveform — لا تتجاوز 100 IRE.', NULL, NULL, NULL),
  ('pp-color-contrast', 'premiere', 'color', ARRAY['كونتراست','contrast','تباين'], 'Contrast', 'الفرق بين الفاتح والغامق. زيادته تعطي صورة أقوى. تقليله يعطي صورة flat (تحتاجها قبل الـ grading).', NULL, NULL, NULL),
  ('pp-color-saturation', 'premiere', 'color', ARRAY['ستيوريشن','saturation','تشبع','ألوان قوية'], 'Saturation', 'Lumetri → Basic → Saturation. يزيد/يقلل قوة الألوان. 0 = أبيض وأسود. الزيادة المفرطة تخرب الصورة.', NULL, NULL, NULL),
  ('pp-color-vibrance', 'premiere', 'color', ARRAY['فايبرنس','vibrance','تشبع ذكي'], 'Vibrance', 'مثل Saturation لكن ذكي — يشبّع الألوان الضعيفة ويحمي البشرة والألوان المشبعة أصلاً. أفضل للبورتريه.', NULL, NULL, NULL),
  ('pp-color-creative', 'premiere', 'color', ARRAY['كرييتف','creative','لوك','ستايل تلوين'], 'Creative Look', 'Lumetri → Creative → Look. قوالب ألوان جاهزة (مثل فلاتر). اختر واحد ثم عدّل Intensity. أو حمّل Look خارجي (.cube).', NULL, NULL, NULL),
  ('pp-color-curves', 'premiere', 'color', ARRAY['كيرفز','curves','منحنيات','تحكم دقيق'], 'Curves', 'Lumetri → Curves. تحكم دقيق جداً. RGB للسطوع، أو اختر قناة (R/G/B) للتلوين. النقطة السفلية = ظلال، العليا = إضاءة.', NULL, NULL, NULL),
  ('pp-color-wheels', 'premiere', 'color', ARRAY['كلر ويلز','color wheels','عجلات الألوان','ظلال','وسط','إضاءة'], 'Color Wheels', 'Lumetri → Color Wheels. ثلاث عجلات: Shadows (ظلال)، Midtones (وسط)، Highlights (إضاءة). اسحب للتلوين. الكلاسيكي: أزرق بالظلال، برتقالي بالإضاءة.', NULL, NULL, NULL),
  ('pp-color-hsl-secondary', 'premiere', 'color', ARRAY['إتش إس إل','HSL secondary','لون معين','تحديد لون'], 'HSL Secondary', 'Lumetri → HSL Secondary. تحدد لون معين وتعدّله. Set Color بالقطارة، وسّع النطاق، ثم عدّل. مثالي لتصحيح البشرة أو السماء.', NULL, NULL, NULL),
  ('pp-color-lut-apply', 'premiere', 'color', ARRAY['لوت','LUT','تطبيق لوت','cube'], 'تطبيق LUT', 'Lumetri → Basic → Input LUT (تقني) أو Creative → Look (إبداعي). Browse واختر ملف .cube. Technical LUTs أولاً، Creative ثانياً.', NULL, NULL, NULL),
  ('pp-color-vignette', 'premiere', 'color', ARRAY['فينيت','vignette','تعتيم الحواف','إطار'], 'Vignette', 'Lumetri → Vignette. Amount سالب = تعتيم، موجب = تفتيح. Midpoint للحجم، Roundness للشكل، Feather للنعومة.', NULL, NULL, NULL),
  ('pp-color-scopes-waveform', 'premiere', 'color', ARRAY['ويفورم سكوب','waveform scope','سطوع','تحليل'], 'Waveform Scope', 'Window → Lumetri Scopes → Waveform. يعرض السطوع من 0 (أسود) لـ 100 (أبيض). حافظ على التفاصيل بين 0-100.', NULL, NULL, NULL),
  ('pp-color-scopes-vectorscope', 'premiere', 'color', ARRAY['فيكتورسكوب','vectorscope','تشبع','لون'], 'Vectorscope', 'يعرض اللون والتشبع. المركز = رمادي، الحافة = مشبع. البشرة الصحية على خط الـ Skin Tone (بين R و Y).', NULL, NULL, NULL),
  ('pp-color-adjustment-layer', 'premiere', 'color', ARRAY['أدجستمنت لاير','adjustment layer','تأثير شامل'], 'Adjustment Layer للتلوين', 'File → New → Adjustment Layer. ضعه فوق الكليبات. أي Lumetri تضيفه يأثر على كل شي تحته. مثالي للـ look الموحد.', NULL, NULL, NULL),
  ('pp-effects-apply', 'premiere', 'effects', ARRAY['تطبيق إفكت','apply effect','إضافة تأثير'], 'تطبيق Effect', 'من لوحة Effects، اسحب الإفكت على الكليب. أو اختر الكليب ودبل كليك على الإفكت. تظهر إعداداته بـ Effect Controls.', NULL, NULL, NULL),
  ('pp-effects-motion', 'premiere', 'effects', ARRAY['موشن','motion','تحريك','بوزيشن','سكيل'], 'Motion Properties', 'Effect Controls → Motion. Position لتحريك، Scale للتكبير، Rotation للدوران، Anchor Point لنقطة الارتكاز.', NULL, NULL, NULL),
  ('pp-effects-opacity', 'premiere', 'effects', ARRAY['أوباسيتي','opacity','شفافية','blend mode'], 'Opacity و Blend Mode', 'Effect Controls → Opacity. غيّر الشفافية (0-100%). Blend Mode يغير طريقة دمج الطبقات (Multiply, Screen, Overlay...).', NULL, NULL, NULL),
  ('pp-effects-time-remapping', 'premiere', 'effects', ARRAY['تايم ريمابنق','time remapping','سلو موشن','تسريع','سرعة متغيرة'], 'Time Remapping', 'كليك يمين على الكليب → Show Clip Keyframes → Time Remapping → Speed. أضف keyframes وغيّر السرعة بين نقطة وأخرى.', NULL, NULL, NULL),
  ('pp-effects-warp-stabilizer', 'premiere', 'effects', ARRAY['وارب ستابلايزر','warp stabilizer','تثبيت','اهتزاز'], 'Warp Stabilizer', 'Effects → Warp Stabilizer. يثبت الفيديو المهتز. Smoothness للقوة. Method: Position أسرع، Subspace Warp أدق لكن أبطأ.', NULL, NULL, NULL),
  ('pp-effects-crop', 'premiere', 'effects', ARRAY['كروب','crop','قص','إطار'], 'Crop Effect', 'Effects → Crop. يقص من الحواف (Left, Right, Top, Bottom). مفيد لإخفاء عناصر أو تغيير aspect ratio.', NULL, NULL, NULL),
  ('pp-effects-blur', 'premiere', 'effects', ARRAY['بلر','blur','ضبابية','تمويه'], 'Gaussian Blur', 'Effects → Gaussian Blur. Blurriness للقوة. استخدمه لتمويه الخلفية أو معلومات حساسة.', NULL, NULL, NULL),
  ('pp-effects-ultra-key', 'premiere', 'effects', ARRAY['ألترا كي','ultra key','كروما','خلفية خضراء','green screen'], 'Ultra Key (Chroma Key)', 'Effects → Ultra Key. Key Color = انقر على الخلفية الخضراء. Setting = Aggressive للخلفيات الصعبة. عدّل Matte لتنظيف الحواف.', NULL, NULL, NULL),
  ('pp-effects-speed-duration', 'premiere', 'effects', ARRAY['سرعة','speed','duration','مدة','تسريع','إبطاء'], 'Speed/Duration', 'كليك يمين → Speed/Duration. غيّر النسبة (200% = ضعف السرعة، 50% = نصف). Reverse Speed للعكس. Maintain Audio Pitch للصوت.', NULL, NULL, NULL),
  ('pp-effects-optical-flow', 'premiere', 'effects', ARRAY['أوبتكال فلو','optical flow','سلو موشن ناعم'], 'Optical Flow للـ Slow Motion', 'Speed/Duration → Time Interpolation → Optical Flow. يخلق فريمات وهمية لسلو موشن ناعم. يحتاج رندر ووقت.', NULL, NULL, NULL),
  ('pp-effects-adjustment-layer', 'premiere', 'effects', ARRAY['أدجستمنت لاير','adjustment layer','طبقة تعديل'], 'Adjustment Layer', 'File → New → Adjustment Layer. ضعها فوق الكليبات. أي إفكت تضيفه يأثر على كل شي تحتها. مثالية للتلوين الموحد.', NULL, NULL, NULL),
  ('pp-titles-text-tool', 'premiere', 'titles', ARRAY['نص','text','عنوان','title','كتابة','T'], 'أداة النص', 'اضغط T أو اختر Text Tool. انقر بالـ Program Monitor واكتب. يُنشئ Graphics layer تلقائياً.', NULL, NULL, NULL),
  ('pp-titles-essential-graphics-edit', 'premiere', 'titles', ARRAY['تعديل نص','edit text','خط','font','حجم'], 'تعديل النص', 'Essential Graphics → Edit. غيّر الخط، الحجم، اللون، المحاذاة. Transform للموقع والدوران. يشتغل على النص أو الشكل المختار.', NULL, NULL, NULL),
  ('pp-titles-mogrt', 'premiere', 'titles', ARRAY['موقرت','MOGRT','قالب','template','أفتر إفكتس'], 'قوالب MOGRT', 'Essential Graphics → Browse → قوالب Adobe أو مثبتة. اسحب للتايم لاين وعدّل النص/الألوان. مصنوعة بـ After Effects.', NULL, NULL, NULL),
  ('pp-captions-auto', 'premiere', 'titles', ARRAY['كابشن','captions','ترجمة تلقائية','transcribe','تفريغ'], 'Auto Transcribe', 'Window → Text. Transcribe sequence → اختر اللغة → Transcribe. ينتج نص ثم Caption → Create captions from transcript.', NULL, NULL, NULL),
  ('pp-captions-export-srt', 'premiere', 'titles', ARRAY['تصدير ترجمة','export SRT','ملف ترجمة'], 'تصدير SRT', 'File → Export → Captions. اختر Format: SRT أو VTT. احفظ الملف. ارفعه ليوتيوب/فيميو أو أي منصة.', NULL, NULL, NULL),
  ('pp-keyframes-add', 'premiere', 'keyframes', ARRAY['إضافة كيفريم','add keyframe','نقطة مفتاحية'], 'إضافة Keyframe', 'Effect Controls → انقر الساعة لتفعيل keyframes → انتقل لفريم آخر → غيّر القيمة → يُضاف keyframe تلقائياً.', NULL, NULL, NULL),
  ('pp-keyframes-interpolation', 'premiere', 'keyframes', ARRAY['إنتربوليشن','interpolation','نوع حركة','ليناير','بيزير'], 'Interpolation', 'كليك يمين على keyframe → Temporal Interpolation. Linear = ثابت، Bezier = قابل للتعديل، Ease In/Out = تباطؤ. أو استخدم الأيقونات.', NULL, NULL, NULL),
  ('pp-keyframes-ease', 'premiere', 'keyframes', ARRAY['إيز','ease','تباطؤ','سلاسة'], 'Ease In / Ease Out', 'كليك يمين على keyframe → Ease In (يبطئ قبل الوصول) أو Ease Out (يبدأ بطيء). يعطي حركة طبيعية.', NULL, NULL, NULL),
  ('pp-multicam-create', 'premiere', 'advanced', ARRAY['ملتي كام','multicam','إنشاء','عدة كاميرات'], 'إنشاء Multicam Sequence', 'اختر كل الزوايا بالـ Project → كليك يمين → Create Multi-Camera Source Sequence. Synchronize By: Audio (الأفضل) أو Timecode.', NULL, NULL, NULL),
  ('pp-multicam-edit', 'premiere', 'advanced', ARRAY['مونتاج ملتي كام','multicam edit','تبديل زوايا'], 'مونتاج Multicam', 'ضع الـ multicam sequence بتايم لاين. شغّل وانقر على الزاوية المطلوبة بالـ Program Monitor (أو أرقام 1-9). يقطع لايف.', NULL, NULL, NULL),
  ('pp-auto-reframe', 'premiere', 'advanced', ARRAY['أوتو ريفريم','auto reframe','تحويل عمودي','9:16'], 'Auto Reframe', 'كليك يمين على sequence بالـ Project → Auto Reframe Sequence. اختر aspect ratio (مثل 9:16 للـ Shorts). يتبع الموضوع تلقائياً.', NULL, NULL, NULL),
  ('pp-scene-edit-detection', 'premiere', 'advanced', ARRAY['سين إديت','scene edit detection','كشف قطعات'], 'Scene Edit Detection', 'كليك يمين على كليب → Scene Edit Detection. يكتشف القطعات ويقسّم الكليب. مفيد لإعادة مونتاج فيديو مصدّر.', NULL, NULL, NULL),
  ('pp-performance-playback-resolution', 'premiere', 'performance', ARRAY['جودة معاينة','playback resolution','1/4','1/2'], 'جودة المعاينة', 'بالـ Program Monitor تحت، غيّر لـ 1/2 أو 1/4. يقلل الجودة للمعاينة فقط — التصدير يبقى كامل الجودة.', NULL, NULL, NULL),
  ('pp-performance-gpu', 'premiere', 'performance', ARRAY['GPU','كرت شاشة','تسريع','Mercury'], 'GPU Acceleration', 'File → Project Settings → General → Renderer. اختر Mercury Playback Engine GPU Acceleration. يستخدم كرت الشاشة للسرعة.', NULL, NULL, NULL),
  ('pp-export-direct', 'premiere', 'export', ARRAY['تصدير مباشر','direct export','Ctrl+M'], 'Export Direct', 'File → Export → Media أو Ctrl+M. اختر الإعدادات → Export. يصدّر مباشرة (يوقف العمل). أو Queue للخلفية.', NULL, NULL, NULL),
  ('pp-export-h264', 'premiere', 'export', ARRAY['H264','MP4','تصدير يوتيوب'], 'تصدير H.264 (MP4)', 'Format: H.264. Preset: YouTube 1080p/4K أو حسب الحاجة. Bitrate: VBR 2-pass للجودة الأفضل. Output مع امتداد .mp4.', NULL, NULL, NULL),
  ('pp-export-prores', 'premiere', 'export', ARRAY['بروريز','ProRes','جودة عالية','ماك'], 'تصدير ProRes', 'Format: QuickTime → Codec: ProRes 422 أو 422 HQ. جودة عالية، حجم كبير. للأرشيف أو الإرسال للتلوين/المكساج.', NULL, NULL, NULL),
  ('pp-export-bitrate', 'premiere', 'export', ARRAY['بت ريت','bitrate','جودة','حجم'], 'Bitrate Settings', 'CBR: ثابت، VBR: متغير (أفضل). 1-pass سريع، 2-pass أدق. YouTube 1080p: ~15-25 Mbps. 4K: ~45-65 Mbps.', NULL, NULL, NULL),
  ('pp-export-youtube-preset', 'premiere', 'export', ARRAY['يوتيوب بريست','YouTube preset','إعدادات يوتيوب'], 'إعدادات YouTube', 'H.264، 1080p أو 4K، VBR 2-pass، ~20-50 Mbps، AAC 320kbps. أو استخدم YouTube preset الجاهز.', NULL, NULL, NULL),
  ('pp-export-instagram', 'premiere', 'export', ARRAY['إنستقرام','Instagram','ريلز','9:16'], 'إعدادات Instagram', 'Reels: 1080×1920 (9:16)، H.264، ~10-15 Mbps. Feed: 1080×1350 (4:5) أو 1080×1080 (1:1). Stories: 1080×1920.', NULL, NULL, NULL),
  ('pp-export-tiktok', 'premiere', 'export', ARRAY['تيك توك','TikTok','شورتس'], 'إعدادات TikTok', '1080×1920 (9:16)، H.264، 30fps أو 60fps، ~8-15 Mbps. مدة: حتى 10 دقائق (3 دقائق مثالي).', NULL, NULL, NULL),
  ('pp-export-alpha', 'premiere', 'export', ARRAY['ألفا','alpha','شفافية','خلفية شفافة'], 'تصدير مع Alpha', 'Format: QuickTime → Codec: GoPro CineForm أو DNxHR. Video → Depth: +Alpha. أو ProRes 4444. الـ H.264 ما يدعم alpha.', NULL, NULL, NULL),
  ('pp-shortcut-c', 'premiere', 'shortcuts', ARRAY['C','razor','قص'], 'C - Razor', 'C يفعّل أداة القص (Razor).', NULL, NULL, NULL),
  ('pp-shortcut-v', 'premiere', 'shortcuts', ARRAY['V','selection','سهم'], 'V - Selection', 'V يفعّل أداة الاختيار (السهم).', NULL, NULL, NULL),
  ('pp-shortcut-ctrl-k', 'premiere', 'shortcuts', ARRAY['Ctrl+K','قص عند المؤشر'], 'Ctrl+K - Cut at Playhead', 'Ctrl+K يقص الكليب المستهدف عند المؤشر.', NULL, NULL, NULL),
  ('pp-shortcut-shift-delete', 'premiere', 'shortcuts', ARRAY['Shift+Delete','ripple delete','حذف وسد'], 'Shift+Delete - Ripple Delete', 'Shift+Delete يحذف ويسد الفراغ.', NULL, NULL, NULL),
  ('pp-shortcut-ctrl-d', 'premiere', 'shortcuts', ARRAY['Ctrl+D','default transition'], 'Ctrl+D - Default Transition', 'Ctrl+D يطبق الترانزيشن الافتراضي.', NULL, NULL, NULL),
  ('pp-shortcut-ctrl-m', 'premiere', 'shortcuts', ARRAY['Ctrl+M','export','تصدير'], 'Ctrl+M - Export', 'Ctrl+M يفتح نافذة التصدير.', NULL, NULL, NULL),
  ('pp-shortcut-i-o', 'premiere', 'shortcuts', ARRAY['I','O','in','out'], 'I/O - In/Out Points', 'I لنقطة البداية، O لنقطة النهاية.', NULL, NULL, NULL),
  ('pp-shortcut-jkl', 'premiere', 'shortcuts', ARRAY['J','K','L','تشغيل'], 'J/K/L - Playback', 'J عكسي، K إيقاف، L تشغيل. مرتين = 2x.', NULL, NULL, NULL),
  ('pp-shortcut-space', 'premiere', 'shortcuts', ARRAY['Space','مسافة','تشغيل'], 'Space - Play/Stop', 'Space تشغيل/إيقاف.', NULL, NULL, NULL),
  ('pp-shortcut-m', 'premiere', 'shortcuts', ARRAY['M','marker','ماركر'], 'M - Add Marker', 'M يضيف marker عند المؤشر.', NULL, NULL, NULL),
  ('pp-shortcut-s', 'premiere', 'shortcuts', ARRAY['S','snap','مغناطيس'], 'S - Snap Toggle', 'S يفعّل/يطفئ المغناطيس.', NULL, NULL, NULL),
  ('pp-shortcut-ctrl-z', 'premiere', 'shortcuts', ARRAY['Ctrl+Z','undo','تراجع'], 'Ctrl+Z - Undo', 'Ctrl+Z تراجع. Ctrl+Shift+Z إعادة.', NULL, NULL, NULL),
  ('pp-shortcut-ctrl-s', 'premiere', 'shortcuts', ARRAY['Ctrl+S','save','حفظ'], 'Ctrl+S - Save', 'Ctrl+S حفظ المشروع.', NULL, NULL, NULL),
  ('pp-shortcut-f', 'premiere', 'shortcuts', ARRAY['F','match frame'], 'F - Match Frame', 'F يفتح الكليب بالـ Source عند الفريم الحالي.', NULL, NULL, NULL),
  ('pp-shortcut-b', 'premiere', 'shortcuts', ARRAY['B','ripple edit'], 'B - Ripple Edit Tool', 'B يفعّل أداة Ripple Edit.', NULL, NULL, NULL),
  ('pp-shortcut-n', 'premiere', 'shortcuts', ARRAY['N','roll edit'], 'N - Roll Edit Tool', 'N يفعّل أداة Roll Edit.', NULL, NULL, NULL),
  ('pp-problem-no-audio', 'premiere', 'problems', ARRAY['صوت ما يشتغل','no audio','مو سامع','صامت'], 'لا صوت بالمعاينة', 'تأكد التراك مو muted (M). تحقق من Audio Hardware بالـ Preferences. جرّب Default Output. تأكد السماعات شغالة بالنظام.', NULL, NULL, NULL),
  ('pp-problem-lag', 'premiere', 'problems', ARRAY['لاق','lag','بطيء','متقطع','ثقيل'], 'المعاينة متقطعة', 'قلل Playback Resolution لـ 1/4. استخدم Proxies. أغلق البرامج الثانية. تأكد الـ GPU acceleration مفعّل. امسح Media Cache.', NULL, NULL, NULL),
  ('pp-problem-crash', 'premiere', 'problems', ARRAY['كراش','crash','يطفي','ينغلق فجأة'], 'البرنامج يكرش', 'حدّث بريمير لآخر إصدار. امسح Media Cache. جرّب بدون GPU (Software Only). استورد المشروع بمشروع جديد.', NULL, NULL, NULL),
  ('pp-problem-media-pending', 'premiere', 'problems', ARRAY['ميديا بندنق','media pending','جاري','ينتظر'], 'Media Pending', 'انتظر يكمل، أو Cancel وابدأ المونتاج. أو Preferences → Media → Enable Accelerated Intel GPU غيّره.', NULL, NULL, NULL),
  ('pp-problem-green-red-frames', 'premiere', 'problems', ARRAY['فريم أخضر','فريم أحمر','green frame','red frame'], 'فريمات خضراء/حمراء', 'مشكلة GPU. Preferences → General → Renderer → Software Only مؤقتاً. حدّث driver كرت الشاشة.', NULL, NULL, NULL),
  ('pp-problem-export-error', 'premiere', 'problems', ARRAY['خطأ تصدير','export error','فشل التصدير'], 'فشل التصدير', 'حدد المنطقة بـ In/Out وصدّر جزء جزء لإيجاد المشكلة. جرّب codec مختلف. صدّر عبر Media Encoder.', NULL, NULL, NULL),
  ('pp-problem-audio-sync', 'premiere', 'problems', ARRAY['تزامن صوت','audio sync','متأخر','مو متطابق'], 'الصوت مو متزامن', 'تأكد frame rate المشروع يطابق الفيديو. غيّر Audio Hardware Buffer Size. أو حرّك الصوت يدوياً.', NULL, NULL, NULL),
  ('pp-problem-offline', 'premiere', 'problems', ARRAY['أوفلاين','offline','ملف مفقود'], 'ملفات Offline', 'كليك يمين → Link Media. حدد الموقع الجديد. أو File → Link Media للكل.', NULL, NULL, NULL),
  ('pp-problem-codec-missing', 'premiere', 'problems', ARRAY['كوديك مفقود','codec missing','ما يقرأ الملف'], 'كوديك مفقود', 'حمّل الكوديك المطلوب (مثل DNxHR لـ Windows). أو حوّل الفيديو لصيغة مدعومة بـ Handbrake أو Media Encoder.', NULL, NULL, NULL),
  ('pp-problem-slow-export', 'premiere', 'problems', ARRAY['تصدير بطيء','slow export','يأخذ وقت'], 'تصدير بطيء', 'استخدم Hardware Encoding (بـ NVIDIA/AMD). قلل الإفكتات الثقيلة. Software VBR 1-pass بدل 2-pass. استخدم SSD للتصدير.', NULL, NULL, NULL),
  ('ae-interface-project', 'aftereffects', 'interface', ARRAY['بروجكت','project','لوحة','ملفات'], 'لوحة Project', 'تعرض كل ملفات وتراكيب المشروع. رتّبها بفولدرات. أنشئ Composition من هنا.', NULL, NULL, NULL),
  ('ae-interface-composition', 'aftereffects', 'interface', ARRAY['كومبوزيشن','composition','comp','تركيب'], 'Composition Panel', 'يعرض نتيجة التركيب. اسحب المؤشر للمعاينة أو Space للتشغيل.', NULL, NULL, NULL),
  ('ae-interface-timeline', 'aftereffects', 'interface', ARRAY['تايم لاين','timeline','لايرات','طبقات'], 'Timeline Panel', 'يعرض اللايرات والـ keyframes والتوقيت. وسّع اللاير لرؤية الخصائص.', NULL, NULL, NULL),
  ('ae-interface-tools', 'aftereffects', 'interface', ARRAY['أدوات','tools','شريط أدوات'], 'شريط الأدوات', 'فوق الشاشة. Selection (V)، Hand (H)، Zoom (Z)، Rotation (W)، Camera (C)، Pen (G)، Text (Ctrl+T)، Shape.', NULL, NULL, NULL),
  ('ae-interface-effects', 'aftereffects', 'interface', ARRAY['إفكتس','effects','تأثيرات','Effects & Presets'], 'Effects & Presets', 'Window → Effects & Presets. ابحث بالاسم واسحب على اللاير.', NULL, NULL, NULL),
  ('ae-layer-solid', 'aftereffects', 'layers', ARRAY['سوليد','solid','لون','خلفية'], 'Solid Layer', 'Layer → New → Solid أو Ctrl+Y. لاير بلون واحد. استخدمه كخلفية أو لتطبيق إفكتات.', NULL, NULL, NULL),
  ('ae-layer-text', 'aftereffects', 'layers', ARRAY['تكست','text','نص','كتابة'], 'Text Layer', 'Ctrl+T أو أداة النص. انقر واكتب. Character للخط والحجم، Paragraph للمحاذاة.', NULL, NULL, NULL),
  ('ae-layer-shape', 'aftereffects', 'layers', ARRAY['شيب','shape','شكل','فيكتور'], 'Shape Layer', 'أدوات الشكل بالأعلى (Rectangle, Ellipse, Star). ترسم vectors قابلة للتحريك بالكامل.', NULL, NULL, NULL),
  ('ae-layer-null', 'aftereffects', 'layers', ARRAY['نل','null','تحكم','كونترولر'], 'Null Object', 'Layer → New → Null Object. لاير غير مرئي للتحكم. Parent لايرات أخرى له وحرّكه مرة وحدة.', NULL, NULL, NULL),
  ('ae-layer-adjustment', 'aftereffects', 'layers', ARRAY['أدجستمنت','adjustment','تأثير شامل'], 'Adjustment Layer', 'Layer → New → Adjustment Layer. أي إفكت تضيفه يأثر على كل شي تحته.', NULL, NULL, NULL),
  ('ae-layer-camera', 'aftereffects', 'layers', ARRAY['كاميرا','camera','3D'], 'Camera Layer', 'Layer → New → Camera. للتصوير 3D. One-Node (ثابتة) أو Two-Node (تتبع نقطة).', NULL, NULL, NULL),
  ('ae-layer-light', 'aftereffects', 'layers', ARRAY['لايت','light','إضاءة','ظل'], 'Light Layer', 'Layer → New → Light. يضيء اللايرات 3D. أنواع: Spot, Point, Parallel, Ambient.', NULL, NULL, NULL),
  ('ae-layer-precomp', 'aftereffects', 'layers', ARRAY['بريكومب','precompose','دمج','تجميع'], 'Pre-compose', 'اختر لايرات → Ctrl+Shift+C. تجمعها بتركيب منفصل. Move All: ينقل كل شي، Leave All: يترك keyframes.', NULL, NULL, NULL),
  ('ae-transform-position', 'aftereffects', 'layers', ARRAY['بوزيشن','position','P','موقع'], 'Position (P)', 'P يظهر Position. القيم [X, Y] أو [X, Y, Z] للـ 3D. حرّك اللاير بالشاشة أو اكتب القيم.', NULL, NULL, NULL),
  ('ae-transform-scale', 'aftereffects', 'layers', ARRAY['سكيل','scale','S','حجم','تكبير'], 'Scale (S)', 'S يظهر Scale. بالنسبة المئوية. Shift+drag للحفاظ على النسبة. الرابط بين X و Y يوحّدهما.', NULL, NULL, NULL),
  ('ae-transform-rotation', 'aftereffects', 'layers', ARRAY['روتيشن','rotation','R','دوران'], 'Rotation (R)', 'R يظهر Rotation. بالدرجات. للـ 3D: X Rotation, Y Rotation, Z Rotation منفصلين.', NULL, NULL, NULL),
  ('ae-transform-opacity', 'aftereffects', 'layers', ARRAY['أوباسيتي','opacity','T','شفافية'], 'Opacity (T)', 'T يظهر Opacity. من 0% (شفاف) لـ 100% (معتم).', NULL, NULL, NULL),
  ('ae-transform-anchor', 'aftereffects', 'layers', ARRAY['أنكر بوينت','anchor point','A','نقطة ارتكاز'], 'Anchor Point (A)', 'A يظهر Anchor Point. نقطة الدوران والتكبير. حرّكها بأداة Pan Behind (Y) أو اكتب القيم.', NULL, NULL, NULL),
  ('ae-keyframe-add', 'aftereffects', 'keyframes', ARRAY['كيفريم','keyframe','إضافة','ساعة'], 'إضافة Keyframe', 'انقر الساعة بجانب الخاصية لتفعيلها. انتقل لوقت آخر وغيّر القيمة — يُضاف keyframe تلقائياً.', NULL, NULL, NULL),
  ('ae-keyframe-u', 'aftereffects', 'keyframes', ARRAY['U','عرض كيفريمز','المفاتيح'], 'U - Show Keyframes', 'U يظهر كل الخصائص التي عليها keyframes. UU (مرتين) يظهر كل الخصائص المعدّلة.', NULL, NULL, NULL),
  ('ae-keyframe-easy-ease', 'aftereffects', 'keyframes', ARRAY['إيزي إيز','easy ease','F9','سلاسة'], 'Easy Ease (F9)', 'اختر keyframe واضغط F9. يضيف تباطؤ في البداية والنهاية. Shift+F9 = Ease In، Ctrl+Shift+F9 = Ease Out.', NULL, NULL, NULL),
  ('ae-keyframe-graph-editor', 'aftereffects', 'keyframes', ARRAY['قراف إديتور','graph editor','منحنى','سرعة'], 'Graph Editor', 'أيقونة الرسم البياني بالتايم لاين. يعرض منحنى القيمة أو السرعة. اسحب المقابض للتحكم الدقيق.', NULL, NULL, NULL),
  ('ae-keyframe-hold', 'aftereffects', 'keyframes', ARRAY['هولد','hold','ثبات','قفز'], 'Hold Keyframe', 'كليك يمين → Keyframe Interpolation → Hold. القيمة تبقى ثابتة ثم تقفز. مثالي للـ on/off.', NULL, NULL, NULL),
  ('ae-expression-wiggle', 'aftereffects', 'expressions', ARRAY['ويقل','wiggle','اهتزاز','عشوائي'], 'wiggle()', 'wiggle(freq, amp) — تردد وسعة. مثال: wiggle(3, 25) = 3 مرات بالثانية، 25 بكسل. للاهتزاز العشوائي.', NULL, NULL, NULL),
  ('ae-expression-loop', 'aftereffects', 'expressions', ARRAY['لوب','loop','تكرار'], 'loopOut()', 'loopOut(''cycle'') يكرر الـ keyframes للأبد. loopOut(''pingpong'') يعكس. loopIn للبداية.', NULL, NULL, NULL),
  ('ae-expression-time', 'aftereffects', 'expressions', ARRAY['تايم','time','وقت','دوران مستمر'], 'time', 'time يرجع الوقت بالثواني. time*360 = دورة كاملة كل ثانية. time*45 = 45 درجة/ثانية.', NULL, NULL, NULL),
  ('ae-expression-value', 'aftereffects', 'expressions', ARRAY['فاليو','value','القيمة الأصلية'], 'value', 'value يرجع القيمة الأصلية. value + wiggle(2,10) يضيف الاهتزاز للقيمة الحالية.', NULL, NULL, NULL),
  ('ae-expression-pickwhip', 'aftereffects', 'expressions', ARRAY['بيك ويب','pickwhip','ربط','سحب'], 'Pickwhip', 'أيقونة الحلزون بجانب الخاصية. اسحبها لخاصية أخرى للربط. يكتب الكود تلقائياً.', NULL, NULL, NULL),
  ('ae-expression-linear', 'aftereffects', 'expressions', ARRAY['لينيار','linear','تحويل نطاق'], 'linear()', 'linear(value, inMin, inMax, outMin, outMax) يحوّل نطاق لآخر. linear(time, 0, 5, 0, 100) = من 0 لـ 100 خلال 5 ثواني.', NULL, NULL, NULL),
  ('ae-expression-random', 'aftereffects', 'expressions', ARRAY['راندوم','random','عشوائي'], 'random()', 'random() يرجع 0-1. random(100) يرجع 0-100. random(50, 100) يرجع بين 50-100. seedRandom(index, true) لتثبيته.', NULL, NULL, NULL),
  ('ae-expression-index', 'aftereffects', 'expressions', ARRAY['إندكس','index','ترتيب اللاير'], 'index', 'index يرجع ترتيب اللاير (أول لاير = 1). index*0.1 يعطي تأخير متتالي لكل لاير.', NULL, NULL, NULL),
  ('ae-mask-create', 'aftereffects', 'masks', ARRAY['ماسك','mask','قناع','إنشاء'], 'إنشاء Mask', 'اختر لاير، ثم ارسم بأداة شكل (Rectangle, Ellipse, Pen). أو دبل كليك على الأداة لماسك بحجم اللاير.', NULL, NULL, NULL),
  ('ae-mask-modes', 'aftereffects', 'masks', ARRAY['موض ماسك','mask modes','Add','Subtract'], 'Mask Modes', 'بالتايم لاين بجانب الماسك. Add: يظهر الداخل. Subtract: يخفي الداخل. Intersect: تقاطع. Difference: فرق.', NULL, NULL, NULL),
  ('ae-mask-feather', 'aftereffects', 'masks', ARRAY['فيذر','feather','نعومة حواف'], 'Mask Feather', 'M M (مرتين) يظهر خصائص الماسك. Feather ينعّم الحواف. Expansion يوسّع/يقلص.', NULL, NULL, NULL),
  ('ae-track-matte', 'aftereffects', 'masks', ARRAY['تراك مات','track matte','ألفا','لوما'], 'Track Matte', 'اللاير يستخدم اللاير فوقه كقناع. Alpha Matte: حسب الشفافية. Luma Matte: حسب السطوع. Inverted يعكس.', NULL, NULL, NULL),
  ('ae-shape-fill-stroke', 'aftereffects', 'shapes', ARRAY['فيل','ستروك','fill','stroke','لون','خط'], 'Fill و Stroke', 'بالـ Shape Layer: Add → Fill للتعبئة، Stroke للحد. غيّر اللون والسماكة من الخصائص.', NULL, NULL, NULL),
  ('ae-shape-repeater', 'aftereffects', 'shapes', ARRAY['ريبيتر','repeater','تكرار','نسخ'], 'Repeater', 'Add → Repeater. يكرر الشكل. Copies للعدد، Offset للموقع، Transform لتعديل كل نسخة.', NULL, NULL, NULL),
  ('ae-shape-trim-paths', 'aftereffects', 'shapes', ARRAY['ترم باثس','trim paths','رسم خط','كتابة'], 'Trim Paths', 'Add → Trim Paths. Start و End يحددان أي جزء يظهر. حرّكهما لتأثير الرسم التدريجي.', NULL, NULL, NULL),
  ('ae-text-animator', 'aftereffects', 'text', ARRAY['تكست أنيميتر','text animator','تحريك حروف'], 'Text Animators', 'وسّع Text Layer → Animate → اختر خاصية. يضيف animator يحرّك كل حرف. Range Selector يحدد النطاق.', NULL, NULL, NULL),
  ('ae-text-range-selector', 'aftereffects', 'text', ARRAY['رينج سيلكتور','range selector','نطاق','offset'], 'Range Selector', 'يحدد أي حروف تتأثر. Start/End للنطاق. Offset لتحريك النطاق (حرّكه للتأثير المتتابع).', NULL, NULL, NULL),
  ('ae-text-presets', 'aftereffects', 'text', ARRAY['بريست نص','text presets','قوالب نص'], 'Text Animation Presets', 'Effects & Presets → Animation Presets → Text. اسحب على النص. قوالب جاهزة للتحريك.', NULL, NULL, NULL),
  ('ae-effect-blur', 'aftereffects', 'effects', ARRAY['بلر','blur','ضبابية','gaussian'], 'Gaussian Blur', 'Effect → Blur → Gaussian Blur. Blurriness للقوة. استخدمه للتركيز أو الخلفية الضبابية.', NULL, NULL, NULL),
  ('ae-effect-glow', 'aftereffects', 'effects', ARRAY['قلو','glow','توهج','إضاءة'], 'Glow', 'Effect → Stylize → Glow. يضيف توهج للمناطق الفاتحة. Threshold يحدد من أين يبدأ، Radius للحجم.', NULL, NULL, NULL),
  ('ae-effect-fractal-noise', 'aftereffects', 'effects', ARRAY['فراكتل نويز','fractal noise','سحب','دخان'], 'Fractal Noise', 'Effect → Noise → Fractal Noise. يولّد أنماط عشوائية (سحب، ضباب، نار). حرّك Evolution للحركة.', NULL, NULL, NULL),
  ('ae-effect-displacement', 'aftereffects', 'effects', ARRAY['دسبليسمنت','displacement','تشويه'], 'Displacement Map', 'Effect → Distort → Displacement Map. يشوّه اللاير حسب لاير آخر. للتأثيرات المائية والحرارية.', NULL, NULL, NULL),
  ('ae-effect-levels', 'aftereffects', 'effects', ARRAY['ليفلز','levels','سطوع','تباين'], 'Levels', 'Effect → Color Correction → Levels. Input يضغط النطاق، Output يوسّعه. للتحكم بالسطوع والتباين.', NULL, NULL, NULL),
  ('ae-effect-curves', 'aftereffects', 'effects', ARRAY['كيرفز','curves','منحنيات ألوان'], 'Curves', 'Effect → Color Correction → Curves. تحكم دقيق جداً. اسحب النقاط على المنحنى. RGB أو قنوات منفصلة.', NULL, NULL, NULL),
  ('ae-effect-hue-sat', 'aftereffects', 'effects', ARRAY['هيو سات','hue saturation','تشبع','لون'], 'Hue/Saturation', 'Effect → Color Correction → Hue/Saturation. Master Hue يغير اللون، Saturation التشبع، Lightness السطوع.', NULL, NULL, NULL),
  ('ae-effect-fill', 'aftereffects', 'effects', ARRAY['فيل إفكت','fill effect','تعبئة لون'], 'Fill Effect', 'Effect → Generate → Fill. يعبئ اللاير بلون واحد. مع ماسك يعبئ منطقة معينة.', NULL, NULL, NULL),
  ('ae-3d-layer', 'aftereffects', '3d', ARRAY['3D لاير','3D layer','ثلاثي الأبعاد'], 'تفعيل 3D', 'أيقونة المكعب بجانب اللاير بالتايم لاين. يفعّل محور Z ويسمح بالتفاعل مع الكاميرا والإضاءة.', NULL, NULL, NULL),
  ('ae-3d-camera-create', 'aftereffects', '3d', ARRAY['إنشاء كاميرا','create camera','كاميرا جديدة'], 'إنشاء Camera', 'Layer → New → Camera. اختر Preset أو عدّل Focal Length (أصغر = زاوية أوسع). One-Node أو Two-Node.', NULL, NULL, NULL),
  ('ae-3d-camera-tools', 'aftereffects', '3d', ARRAY['أدوات كاميرا','camera tools','C','orbit'], 'أدوات الكاميرا', 'C يدور بين أدوات الكاميرا: Orbit (دوران)، Track XY (تحريك)، Track Z (zoom). أو اضغط مع Alt لتحريك مؤقت.', NULL, NULL, NULL),
  ('ae-3d-light-types', 'aftereffects', '3d', ARRAY['أنواع إضاءة','light types','سبوت','بوينت'], 'أنواع الإضاءة', 'Spot: مخروط موجه. Point: ينتشر لكل الاتجاهات. Parallel: أشعة متوازية (شمس). Ambient: عام بدون ظل.', NULL, NULL, NULL),
  ('ae-3d-depth-of-field', 'aftereffects', '3d', ARRAY['دبث أوف فيلد','depth of field','DOF','عمق الميدان'], 'Depth of Field', 'Camera Options → Enable Depth of Field: On. Focus Distance لنقطة التركيز. Aperture لقوة الضبابية.', NULL, NULL, NULL),
  ('ae-tracking-point', 'aftereffects', 'tracking', ARRAY['بوينت تراكنق','point tracking','تتبع نقطة'], 'Point Tracking', 'Window → Tracker. Track Motion. حدد النقطة وحلّل. Apply لتطبيق على لاير. Position، Rotation، Scale.', NULL, NULL, NULL),
  ('ae-tracking-stabilize', 'aftereffects', 'tracking', ARRAY['ستابلايز','stabilize','تثبيت'], 'Stabilize Motion', 'Tracker → Stabilize Motion. حلّل الحركة ثم Apply. يثبت الفيديو المهتز. قد تحتاج scale up للحواف.', NULL, NULL, NULL),
  ('ae-tracking-3d-camera', 'aftereffects', 'tracking', ARRAY['3D كاميرا تراكر','3D camera tracker','تتبع كاميرا'], '3D Camera Tracker', 'Effect → 3D Camera Tracker. يحلّل ويعطي نقاط 3D. كليك يمين على نقاط → Create Null and Camera. للإدراج ثلاثي الأبعاد.', NULL, NULL, NULL),
  ('ae-roto-brush', 'aftereffects', 'rotoscope', ARRAY['روتو برش','roto brush','قص شخص','عزل'], 'Roto Brush', 'اختر Roto Brush Tool (Alt+W). ارسم داخل الموضوع (أخضر). Propagate للفريمات التالية. Refine Edge للحواف.', NULL, NULL, NULL),
  ('ae-content-aware-fill', 'aftereffects', 'rotoscope', ARRAY['كونتنت أوير فيل','content aware fill','إزالة عنصر'], 'Content Aware Fill', 'ارسم ماسك حول الشي المراد إزالته. Window → Content-Aware Fill. Generate Fill Layer. يملأ بالخلفية.', NULL, NULL, NULL),
  ('ae-parent-child', 'aftereffects', 'compositing', ARRAY['بيرنت','parent','ربط','تبعية'], 'Parenting', 'اسحب الـ pickwhip من لاير للاير الأب. أو اختر من القائمة. الابن يتبع حركة الأب.', NULL, NULL, NULL),
  ('ae-collapse-transform', 'aftereffects', 'compositing', ARRAY['كولابس','collapse transformations','نجمة'], 'Collapse Transformations', 'أيقونة النجمة/الشمس. يحافظ على جودة الـ precomp عند التكبير. ويمرر 3D والـ blending modes.', NULL, NULL, NULL),
  ('ae-render-queue', 'aftereffects', 'render', ARRAY['رندر كيو','render queue','تصدير'], 'Render Queue', 'Composition → Add to Render Queue أو Ctrl+M. Output Module للإعدادات، Output To للمكان. Render.', NULL, NULL, NULL),
  ('ae-output-module', 'aftereffects', 'render', ARRAY['آوتبت مودل','output module','كوديك'], 'Output Module', 'Format: QuickTime أو AVI. Codec: ProRes, DNxHR, Animation (lossless). Channels: RGB+Alpha للشفافية.', NULL, NULL, NULL),
  ('ae-media-encoder', 'aftereffects', 'render', ARRAY['ميديا إنكودر','media encoder','AME','خلفية'], 'Adobe Media Encoder', 'Composition → Add to Adobe Media Encoder Queue. يصدّر بالخلفية. H.264 للويب، ProRes للجودة.', NULL, NULL, NULL),
  ('ae-render-alpha', 'aftereffects', 'render', ARRAY['رندر ألفا','render alpha','شفافية'], 'تصدير مع Alpha', 'Output Module → Channels: RGB+Alpha. Format: QuickTime مع ProRes 4444 أو Animation. PNG Sequence أيضاً يدعم.', NULL, NULL, NULL),
  ('ae-performance-ram', 'aftereffects', 'performance', ARRAY['رام','RAM','ذاكرة','preview'], 'RAM Preview', 'Space أو 0 (Numpad). يرندر ويخزن بالذاكرة. الخط الأخضر = cached. Preferences → Memory لتخصيص RAM.', NULL, NULL, NULL),
  ('ae-performance-cache', 'aftereffects', 'performance', ARRAY['كاش','disk cache','تخزين'], 'Disk Cache', 'Preferences → Media & Disk Cache. حدد مجلد على SSD سريع. Empty Disk Cache لتفريغه.', NULL, NULL, NULL),
  ('ae-performance-purge', 'aftereffects', 'performance', ARRAY['بيرج','purge','تفريغ ذاكرة'], 'Purge Memory', 'Edit → Purge → All Memory & Disk Cache. يفرّغ الذاكرة والكاش. استخدمه إذا البرنامج بطيء.', NULL, NULL, NULL),
  ('ae-problem-ram-preview', 'aftereffects', 'problems', ARRAY['رام بريفيو بطيء','slow preview','معاينة بطيئة'], 'RAM Preview بطيء', 'قلل Resolution لـ Half أو Quarter. أغلق اللايرات غير المرئية. Precomp الأجزاء الثقيلة.', NULL, NULL, NULL),
  ('ae-problem-expression', 'aftereffects', 'problems', ARRAY['خطأ إكسبريشن','expression error','أحمر'], 'خطأ Expression', 'الخطأ يظهر بالتايم لاين. تحقق من الأقواس، الفواصل، أسماء اللايرات. انقر على الخطأ لرؤية التفاصيل.', NULL, NULL, NULL),
  ('ae-problem-missing-font', 'aftereffects', 'problems', ARRAY['خط مفقود','missing font','فونت'], 'خط مفقود', 'يظهر تحذير أصفر. حمّل الخط المطلوب أو استبدله: كليك يمين على النص → Replace Font.', NULL, NULL, NULL),
  ('ae-problem-render-fail', 'aftereffects', 'problems', ARRAY['فشل رندر','render failed','خطأ تصدير'], 'فشل الرندر', 'جرّب منطقة أصغر لإيجاد المشكلة. أطفئ الإفكتات واحد واحد. تأكد من مساحة القرص. جرّب codec مختلف.', NULL, NULL, NULL),
  ('ae-problem-footage-missing', 'aftereffects', 'problems', ARRAY['فوتج مفقود','missing footage','ملف ضايع'], 'Footage مفقود', 'يظهر بالـ Project بلون. كليك يمين → Replace Footage → File. أو File → Dependencies → Find Missing Footage.', NULL, NULL, NULL),
  ('fg-basics-frame', 'figma', 'basics', ARRAY['فريم','frame','إطار','F'], 'Frame', 'F ثم اسحب. أو اختر preset من اليمين (iPhone, Desktop...). الفريم مثل الـ artboard — يحتوي التصميم.', NULL, NULL, NULL),
  ('fg-basics-group', 'figma', 'basics', ARRAY['قروب','group','تجميع','Ctrl+G'], 'Group', 'اختر عناصر → Ctrl+G. تتحرك معاً. الفرق عن Frame: الـ Group ما يقص المحتوى ولا يدعم Auto Layout.', NULL, NULL, NULL),
  ('fg-basics-constraints', 'figma', 'basics', ARRAY['كونسترينتس','constraints','تقييد','responsive'], 'Constraints', 'بالـ Design panel يمين. Left, Right, Center, Scale... تحدد كيف يتصرف العنصر لما يتغير حجم الـ Frame الأب.', NULL, NULL, NULL),
  ('fg-component-create', 'figma', 'components', ARRAY['كومبوننت','component','إنشاء','Ctrl+Alt+K'], 'إنشاء Component', 'اختر العنصر → Ctrl+Alt+K أو كليك يمين → Create Component. يصير قابل لإعادة الاستخدام (instances).', NULL, NULL, NULL),
  ('fg-component-instance', 'figma', 'components', ARRAY['إنستنس','instance','نسخة'], 'Instance', 'اسحب الـ component من Assets أو انسخه. التعديل على الـ main يأثر على كل الـ instances.', NULL, NULL, NULL),
  ('fg-component-variant', 'figma', 'components', ARRAY['فاريانت','variant','حالات'], 'Variants', 'اختر components متشابهة → Combine as Variants. تصير حالات مختلفة (مثل Button: default, hover, disabled).', NULL, NULL, NULL),
  ('fg-autolayout-basic', 'figma', 'auto-layout', ARRAY['أوتو ليوت','auto layout','ترتيب تلقائي','Shift+A'], 'Auto Layout', 'اختر frame أو عناصر → Shift+A. يرتّب المحتوى تلقائياً. يتكيف مع المحتوى.', NULL, NULL, NULL),
  ('fg-autolayout-direction', 'figma', 'auto-layout', ARRAY['اتجاه','direction','أفقي','عمودي'], 'Direction', 'بالـ Design panel: سهم يمين = أفقي، سهم تحت = عمودي. Wrap ينزل للسطر الثاني.', NULL, NULL, NULL),
  ('fg-autolayout-padding', 'figma', 'auto-layout', ARRAY['بادنق','padding','هامش داخلي'], 'Padding و Gap', 'Padding: المسافة من الحواف. Gap: المسافة بين العناصر. اضغط على الأرقام لتعديلها.', NULL, NULL, NULL),
  ('fg-vector-pen', 'figma', 'vector', ARRAY['بن تول','pen tool','P','رسم'], 'Pen Tool', 'P للرسم الحر. انقر للنقاط المستقيمة، اسحب للمنحنيات. Enter للإنهاء. دبل كليك على نقطة لتعديلها.', NULL, NULL, NULL),
  ('fg-vector-boolean', 'figma', 'vector', ARRAY['بوليان','boolean','دمج','Union'], 'Boolean Operations', 'اختر شكلين → أيقونة Boolean بالأعلى. Union يدمج، Subtract يطرح، Intersect التقاطع، Exclude يستثني.', NULL, NULL, NULL),
  ('fg-text-styles', 'figma', 'text', ARRAY['ستايل نص','text style','تنسيق'], 'Text Styles', 'صمم النص → كليك يمين → Create Style. سمّه (مثل H1, Body). طبّقه من الـ Text panel.', NULL, NULL, NULL),
  ('fg-color-styles', 'figma', 'text', ARRAY['ستايل لون','color style','ألوان'], 'Color Styles', 'اختر لون → أيقونة 4 نقاط → +. سمّه (Primary, Background...). يسهّل تغيير الألوان لاحقاً.', NULL, NULL, NULL),
  ('fg-export-png', 'figma', 'export', ARRAY['تصدير PNG','export PNG','صورة'], 'تصدير PNG', 'اختر العنصر → Export بالأسفل يمين. + لإضافة تصدير. PNG للصور العادية. 2x أو 3x للـ retina.', NULL, NULL, NULL),
  ('fg-export-svg', 'figma', 'export', ARRAY['تصدير SVG','export SVG','فيكتور'], 'تصدير SVG', 'للأيقونات والرسومات. قابل للتكبير بدون فقدان الجودة. تأكد من Outline Stroke قبل التصدير.', NULL, NULL, NULL),
  ('fg-plugin-unsplash', 'figma', 'plugins', ARRAY['أنسبلاش','unsplash','صور مجانية'], 'Unsplash Plugin', 'Plugins → Unsplash. صور مجانية عالية الجودة. ابحث واسحب مباشرة للتصميم.', NULL, NULL, NULL),
  ('fg-plugin-iconify', 'figma', 'plugins', ARRAY['أيقونات','iconify','icons'], 'Iconify', 'Plugins → Iconify. آلاف الأيقونات المجانية. ابحث وأدرج. قابلة للتعديل.', NULL, NULL, NULL),
  ('fg-thumbnail-workflow', 'figma', 'youtube-thumbnails', ARRAY['ثمنيل','thumbnail','يوتيوب','صورة مصغرة'], 'Workflow ثمنيلات YouTube', 'Frame: 1280×720. خلفية جذابة. وجه واضح كبير. نص قصير بخط عريض. ألوان متباينة. تصدير PNG.', NULL, NULL, NULL),
  ('fg-thumbnail-size', 'figma', 'youtube-thumbnails', ARRAY['حجم ثمنيل','thumbnail size','أبعاد'], 'أبعاد الثمنيل', '1280×720 بكسل (16:9). أو 1920×1080 للجودة العالية. الحد الأقصى 2MB.', NULL, NULL, NULL),
  ('fg-thumbnail-text', 'figma', 'youtube-thumbnails', ARRAY['نص ثمنيل','thumbnail text','خط'], 'النص بالثمنيل', '3-5 كلمات كحد أقصى. خط عريض (Bold/Black). لون متباين مع الخلفية. حدود (stroke) للوضوح.', NULL, NULL, NULL),
  ('cross-youtube-settings', 'cross', 'export-presets', ARRAY['يوتيوب','YouTube','إعدادات تصدير'], 'إعدادات YouTube', '1920×1080 أو 3840×2160 (4K). H.264 أو H.265. VBR 2-pass. 1080p: 15-25 Mbps، 4K: 45-65 Mbps. AAC 320kbps.', NULL, NULL, NULL),
  ('cross-instagram-feed', 'cross', 'export-presets', ARRAY['إنستقرام فيد','Instagram feed','مربع'], 'إعدادات Instagram Feed', '1080×1080 (1:1) أو 1080×1350 (4:5). H.264. 8-12 Mbps. 60 ثانية كحد أقصى.', NULL, NULL, NULL),
  ('cross-instagram-reels', 'cross', 'export-presets', ARRAY['ريلز','Reels','إنستقرام عمودي'], 'إعدادات Reels', '1080×1920 (9:16). H.264. 10-15 Mbps. 30fps أو 60fps. حتى 90 ثانية.', NULL, NULL, NULL),
  ('cross-tiktok', 'cross', 'export-presets', ARRAY['تيك توك','TikTok'], 'إعدادات TikTok', '1080×1920 (9:16). H.264. 8-15 Mbps. 30 أو 60fps. حتى 10 دقائق (3 دقائق مثالي).', NULL, NULL, NULL),
  ('cross-twitter', 'cross', 'export-presets', ARRAY['تويتر','Twitter','X'], 'إعدادات Twitter/X', '1920×1080 (16:9) أو 1080×1080 (1:1). H.264. 5-8 Mbps. 2:20 كحد أقصى.', NULL, NULL, NULL),
  ('cross-aspect-16-9', 'cross', 'aspect-ratios', ARRAY['16:9','أفقي','landscape','يوتيوب'], '16:9 Landscape', '1920×1080 (Full HD) أو 3840×2160 (4K). YouTube، TV، العرض الأفقي. الأكثر شيوعاً.', NULL, NULL, NULL),
  ('cross-aspect-9-16', 'cross', 'aspect-ratios', ARRAY['9:16','عمودي','vertical','موبايل'], '9:16 Vertical', '1080×1920. Reels، TikTok، Stories، Shorts. للموبايل.', NULL, NULL, NULL),
  ('cross-aspect-1-1', 'cross', 'aspect-ratios', ARRAY['1:1','مربع','square'], '1:1 Square', '1080×1080. Instagram Feed الكلاسيكي. يعمل على كل المنصات.', NULL, NULL, NULL),
  ('cross-aspect-4-5', 'cross', 'aspect-ratios', ARRAY['4:5','بورتريه','portrait'], '4:5 Portrait', '1080×1350. Instagram Feed (يأخذ مساحة أكبر من المربع). بين العمودي والمربع.', NULL, NULL, NULL),
  ('cross-safe-zones', 'cross', 'aspect-ratios', ARRAY['سيف زون','safe zone','منطقة آمنة'], 'Safe Zones', 'للعمودي (9:16): Title Safe بالوسط 840×1250 تقريباً. تجنب الـ 150px فوق/تحت للـ UI. اترك هامش 5% للشاشات.', NULL, NULL, NULL),
  ('cross-codec-h264', 'cross', 'codecs', ARRAY['H264','كوديك','MP4','AVC'], 'H.264 (AVC)', 'الأكثر توافقاً. حجم معقول وجودة جيدة. يدعمه كل شي. الخيار الآمن للويب.', NULL, NULL, NULL),
  ('cross-codec-h265', 'cross', 'codecs', ARRAY['H265','HEVC','كوديك حديث'], 'H.265 (HEVC)', 'جودة أفضل بنفس الحجم (أو نصف الحجم بنفس الجودة). أبطأ بالتصدير. مو كل الأجهزة تدعمه.', NULL, NULL, NULL),
  ('cross-codec-prores', 'cross', 'codecs', ARRAY['بروريز','ProRes','كوديك احترافي'], 'ProRes', 'Apple. جودة عالية، حجم كبير. للأرشيف والتعديل. أنواع: 422 LT، 422، 422 HQ، 4444 (مع alpha).', NULL, NULL, NULL),
  ('cross-codec-dnxhr', 'cross', 'codecs', ARRAY['DNxHR','كوديك أفيد'], 'DNxHR', 'Avid. بديل ProRes لـ Windows. جودة عالية. أنواع: LB، SQ، HQ، HQX، 444.', NULL, NULL, NULL),
  ('cross-bitrate-explained', 'cross', 'codecs', ARRAY['بت ريت','bitrate','جودة حجم'], 'فهم Bitrate', 'كم بيانات بالثانية. أعلى = جودة أفضل + حجم أكبر. CBR ثابت، VBR متغير (أفضل). 1-pass سريع، 2-pass أدق.', NULL, NULL, NULL),
  ('cross-container-mp4', 'cross', 'codecs', ARRAY['MP4','حاوية','container'], 'MP4 Container', 'الأكثر توافقاً. يحتوي H.264 أو H.265. للويب والتوزيع.', NULL, NULL, NULL),
  ('cross-container-mov', 'cross', 'codecs', ARRAY['MOV','كويك تايم','QuickTime'], 'MOV Container', 'Apple QuickTime. يحتوي ProRes وغيره. للإنتاج الاحترافي. ممتاز على Mac.', NULL, NULL, NULL),
  ('cross-color-rec709', 'cross', 'color-management', ARRAY['ريك 709','Rec.709','SDR'], 'Rec.709', 'معيار HD. الألوان القياسية للتلفزيون والويب. استخدمه دائماً إلا إذا تعمل HDR.', NULL, NULL, NULL),
  ('cross-color-srgb', 'cross', 'color-management', ARRAY['sRGB','ويب','ألوان ويب'], 'sRGB', 'معيار الويب والشاشات. قريب جداً من Rec.709. للصور والـ graphics.', NULL, NULL, NULL),
  ('cross-color-bit-depth', 'cross', 'color-management', ARRAY['بت دبث','bit depth','8 بت','10 بت'], 'Bit Depth', '8-bit: 16.7 مليون لون، كافي للويب. 10-bit: مليار لون، للتلوين الاحترافي. 12-bit: للسينما.', NULL, NULL, NULL),
  ('cross-file-organization', 'cross', 'file-organization', ARRAY['تنظيم ملفات','folder structure','ترتيب'], 'هيكل المجلدات', 'Project/ → 01_Footage/ → 02_Audio/ → 03_Graphics/ → 04_Exports/ → 05_Project_Files/. رقّم للترتيب.', NULL, NULL, NULL),
  ('cross-naming-convention', 'cross', 'file-organization', ARRAY['تسمية ملفات','naming','اسم ملف'], 'تسمية الملفات', 'ProjectName_Version_Date. مثال: Nike_Ad_v03_2024-01-15. لا فراغات (استخدم _ أو -). لا أحرف خاصة.', NULL, NULL, NULL),
  ('cross-version-control', 'cross', 'file-organization', ARRAY['فيرجن','version','نسخ'], 'Version Control', 'احفظ نسخ: v01، v02، v03. لا تعدّل على v01 — احفظ كـ v02. النسخة النهائية: _FINAL أو _MASTER.', NULL, NULL, NULL),
  ('cross-hardware-ram', 'cross', 'hardware', ARRAY['رام','RAM','ذاكرة','كم رام'], 'RAM الموصى به', '16GB: الحد الأدنى. 32GB: مريح. 64GB: للـ 4K والمشاريع الكبيرة. After Effects يأكل RAM.', NULL, NULL, NULL),
  ('cross-hardware-gpu', 'cross', 'hardware', ARRAY['GPU','كرت شاشة','graphics card'], 'GPU', 'NVIDIA أو AMD حديث. VRAM: 6GB+ للـ 1080p، 8GB+ للـ 4K. يسرّع الإفكتات والتصدير (NVENC/AMF).', NULL, NULL, NULL),
  ('cross-hardware-storage', 'cross', 'hardware', ARRAY['تخزين','SSD','هارد'], 'Storage', 'SSD للنظام والبرامج والـ cache. HDD كبير للأرشيف. NVMe أسرع من SATA SSD.', NULL, NULL, NULL)
